const params = $('Fetch Plan').first().json;
const q = $input.first().json;

const brain = q.brain;
if (!brain || brain.length === 0) {
  return [{ json: {
    _hasBrain: false,
    client_id: params.client_id,
    client_name: params.client_name,
    message: 'No Brain insights found for ' + params.client_name + '. Run Brain Analysis first.'
  }}];
}

return [{ json: {
  _hasBrain: true,
  ...params,
  _data: q
}}];

const params = $input.first().json;
const data = params._data;
const brain = data.brain[0]?.insights || data.brain[0];

// Approved theme from the plan
const theme_name = params.theme_name || '';
const theme_emoji = params.theme_emoji || '';
const theme_direction = params.theme_direction || '';
const theme_seed = params.theme_seed || '';

const isGenericFallback = params.approved_by === 'generic_fallback';

// Build context sections
const recentThemes = (data.recent_plans || [])
  .map(p => p.theme_emoji + ' ' + p.theme_name + ' (' + p.week_start + ')')
  .join('\n- ') || 'None yet';

const avatarList = (data.avatars || [])
  .map(a => a.person_name + ' / ' + a.style_name + ' (' + a.motion_preset + ') [id:' + a.id + ']')
  .join('\n- ') || 'No avatars configured';

const bgList = (data.backgrounds || [])
  .map(b => b.label + ' [' + (b.category || 'uncategorized') + '] (id:' + b.id + ')')
  .join('\n- ') || 'No backgrounds configured';

const musicList = (data.music || [])
  .map(m => (m.song_title || m.song_id) + ' [' + (m.genre || 'unknown') + '] (song_id:' + m.song_id + ')')
  .join('\n- ') || 'No music configured';

// Include bg_categories in the template list so Claude knows which backgrounds match
const templateList = (data.templates || [])
  .map(t => {
    let desc = t.name + ' (' + t.asset_type + ', ' + t.item_count_min + '-' + t.item_count_max + ' items';
    if (t.bg_categories && t.bg_categories.length > 0) {
      desc += ', bg_categories: ' + JSON.stringify(t.bg_categories);
    }
    desc += ') [id:' + t.id + ']';
    return desc;
  })
  .join('\n- ') || 'No templates configured';

const platformList = (data.platforms || []).map(p => p.platform).join(', ') || 'None configured';

const adTypesList = (data.ad_types || [])
  .map(t => t.asset_type)
  .join(', ') || 'None configured';

const inv = data.inventory_summary || {};
const invSummary = 'Total: ' + (inv.total_count || 0) +
  ', Aged (45+ days): ' + (inv.aged_count || 0) +
  ', New arrivals (7 days): ' + (inv.new_arrivals || 0) +
  ', Price range: $' + (inv.min_price || 0) + ' - $' + (inv.max_price || 0) +
  ', Avg: $' + (inv.avg_price || 0);

// Inventory target suggestion based on aged count
const agedCount = inv.aged_count || 0;
const inventoryTargetHint = agedCount >= 3
  ? 'SUGGESTION: There are ' + agedCount + ' aged vehicles (45+ days). Consider setting inventory_target to "Aged Inventory" to move these units.'
  : 'SUGGESTION: Few aged vehicles. Consider "Recent Arrivals" or "Budget Friendly" for inventory_target.';

const featuredVehicles = (data.featured_inventory || [])
  .slice(0, 20)
  .map(v => v.title + ' ($' + v.price + ', ' + (v.days_on_lot || 0) + ' days) [id:' + v.id + ']')
  .join('\n- ') || 'No inventory available';

// Build placement list dynamically from DB, filtered to enabled platforms
const enabledPlatforms = new Set((data.platforms || []).map(p => p.platform));
const allPlacements = (data.placements_data || []);
const availablePlacements = allPlacements.filter(p => enabledPlatforms.has(p.platform));
const placementListText = availablePlacements.length > 0
  ? availablePlacements.map(p => {
      const ratios = (p.aspect_ratios || []).join(', ');
      const types = (p.supported_asset_types || []).join(', ');
      return '- ' + p.code + ' (' + p.platform + ' ' + p.placement + '): ' + ratios + ' — ' + types;
    }).join('\n')
  : 'No placements configured';


const themeSection = isGenericFallback
  ? `## Theme Direction (Generic — Creative Freedom)
The client did not approve a specific theme this week. You have creative freedom to generate an appropriate theme.
${theme_direction ? `The system suggested: "${theme_direction}" — you may use this as inspiration or create something better.` : ''}
${theme_seed ? `Seed idea: ${theme_seed}` : ''}

Generate a theme that:
- Is relevant to the current season/time of year
- Aligns with what's performing well (see Brain insights)
- Features inventory that needs to move (aging stock, new arrivals)
- Feels fresh compared to recent themes`
  : `## Approved Theme
The client has already approved this theme:
- Name: ${theme_name}
- Emoji: ${theme_emoji}
- Direction: ${theme_direction}
- Seed: ${theme_seed}

You MUST use this exact theme. Do NOT generate a new theme.`;

const userPrompt = `${themeSection}

## This Week
Week of: ${params.week_start} to ${params.week_end}
Client: ${params.client_name} (${params.slug})
Industry: ${params.industry}

## Brain Insights (from last analysis)
${JSON.stringify(brain, null, 2)}

## Recent Themes (for context)
- ${recentThemes}

## Available Creative Assets

### Avatars
- ${avatarList}

### Backgrounds
- ${bgList}

### Music
- ${musicList}

### Templates
- ${templateList}

### Platforms
${platformList}

### Enabled Ad Types
${adTypesList}

## Placement Targeting
The Brain recommends these placement priorities:
- Focus: ${(brain.recommendations?.placement_mix?.focus || []).join(', ') || 'Not specified'}
- Reduce: ${(brain.recommendations?.placement_mix?.reduce || []).join(', ') || 'None'}
- Exclude: ${(brain.recommendations?.placement_mix?.exclude || []).join(', ') || 'None'}
- Rationale: ${brain.recommendations?.placement_mix?.notes || 'No placement data yet'}

Available placements and their constraints:
${placementListText}

## Background-Template Matching Rules
Each template may have a bg_categories list (e.g., ["exterior", "themed"]). When selecting a background for a video asset, you MUST pick a background whose category is in the template's bg_categories list. If a template has no bg_categories, any background is allowed.

## Inventory
${invSummary}
${inventoryTargetHint}

### Top Vehicles (by days on lot)
- ${featuredVehicles}

## Ad Type Details
- **video**: Requires a template, avatar, background, music. Used for video ads and organic/educational content.
- **image**: Catalog-driven "Always On" image ad. No template needed — just ad copy (primary_text, headline, description). Runs continuously on Meta feeds.
- **carousel**: Catalog-driven "Always On" carousel ad. No template needed — just ad copy. Shows multiple products from the inventory catalog.
- **spark**: Boosted organic post. No template needed — selects a top-performing organic post to boost with a budget. Set default budget of $100 for 7 days.

## Budget
Weekly ad budget: $${params.weekly_budget || "Not set"}
Allocate budget_percentage across paid assets so they sum to 100.

## Instructions
Build the full asset plan around the approved theme above. Use the Brain insights to inform your creative direction and inventory strategy. The theme has already been approved — focus on selecting the best assets, placements, and inventory to maximize performance.`;

return [{ json: {
  ...params,
  _userPrompt: userPrompt,
  _approvers: data.approvers || [],
  isGenericFallback: isGenericFallback
}}];

const data = $input.first().json;
const isGenericFallback = data.isGenericFallback || false;

let systemPrompt = "You are the Planner — Ad Pilot's content planning agent for local business advertising.

The theme has already been approved by the client. You MUST use the approved theme name, emoji, seed, and direction exactly as provided. Focus on building the best possible asset plan around that theme.

Your job is to create a weekly content plan that includes specific ad assets and organic content recommendations based on the approved theme. You use insights from the Brain (performance analysis agent) to make data-driven decisions.

## Your output must be valid JSON matching this exact schema:

{
  "theme": {
    "name": "string — USE THE APPROVED THEME NAME EXACTLY",
    "emoji": "string — USE THE APPROVED EMOJI EXACTLY",
    "theme_seed": "string — USE THE APPROVED SEED EXACTLY",
    "direction": "string — USE THE APPROVED DIRECTION EXACTLY",
    "ad_message": "string — core message for paid ads this week",
    "edu_message": "string — educational/organic content angle"
  },
  "inventory_target": "string — one of: 'Aged Inventory', 'Recent Arrivals', 'Budget Friendly', 'Featured Products', 'Premium Picks'",
  "inventory_description": "string — 1 sentence explaining why this inventory target was chosen",
  "experiment": {
    "name": "string — short name for this week's creative experiment (e.g., '18-45 Audience Segment')",
    "goal": "string — what we hope to learn (e.g., 'Increase engagement from the 18-45 demographic.')",
    "approach": "string — how we'll test it (e.g., 'Testing shorter hooks on vertical platforms.')"
  },
  "always_on": {
    "status": "active | paused — whether catalog/DPA ads should stay active this week",
    "copy_refresh": "boolean — true if catalog ad copy should be refreshed",
    "copy_direction": "string or null — direction for new copy if copy_refresh is true"
  },
  "assets": [
    {
      "asset_type": "paid | organic",
      "ad_format": "video | image | carousel | spark",
      "template_id": "uuid of selected template (null for image/carousel/spark)",
      "template_name": "name of template (or 'Image Ad' / 'Carousel Ad' / 'Spark Ad')",
      "title": "string — descriptive strategic title for this asset (NOT the template name)",
      "avatar_id": "uuid of selected avatar (null for image/carousel/spark)",
      "avatar_name": "display name of avatar (null for image/carousel/spark)",
      "background_id": "uuid — REQUIRED for video assets, null for image/carousel/spark",
      "background_name": "string — label of the background (REQUIRED for video assets, null for others)",
      "music_id": "song_id string — REQUIRED for video assets, null for image/carousel/spark",
      "music_name": "string — name/title of the song (REQUIRED for video assets, null for others)",
      "target_length": "brief | standard | extended (video only)",
      "budget_percentage": "number — percentage of weekly ad budget for this asset (paid assets only, must sum to 100 across all paid assets)",
      "inventory_items": [
        { "id": "uuid", "display": "vehicle title" }
      ],
      "target_placements": ["fb_feed", "ig_reels"],
      "ad_copy": {
        "primaryText": "string — main ad text (for image/carousel only)",
        "headline": "string — short headline (for image/carousel only)",
        "description": "string — description line (for image/carousel only)",
        "callToAction": "Shop Now | Learn More | Get Offer"
      },
      "boost_metrics": {
        "budget": 100,
        "duration": 7,
        "targetAudience": "string description (for spark only)"
      },
      "organic_content_type": "string — for organic assets: educational | behind_the_scenes | testimonial | tip | how_to",
      "organic_platform": "string — for organic assets: tiktok | instagram | facebook",
      "organic_day_of_week": "string — suggested day to post: Monday | Tuesday | ... | Sunday",
      "organic_brief": "string — 1-2 sentence brief for the organic post",
      "rationale": "Why this combination works for this week's goals"
    }
  ],
  "organic_posts": [
    {
      "type": "educational | behind_the_scenes | testimonial | tip",
      "topic": "What this post is about",
      "platform": "tiktok | instagram | facebook",
      "hook": "Opening line to grab attention"
    }
  ],
  "idea_ping_summary": "string — 2-3 sentence summary of the plan. Explain what the ads will focus on. Keep it conversational and exciting."
}

## Rules:
1. Use the APPROVED THEME exactly as provided — do NOT generate a new theme name, emoji, seed, or direction.
2. Use Brain insights to inform decisions (e.g., if Multi-Item templates perform best, prioritize them).
3. Feature aged inventory (45+ days) when available — these need exposure.
4. Create EXACTLY 1 paid video asset per enabled template type. Do NOT create duplicates — one Multi Item, one Spotlight, etc.
5. Include EXACTLY 1 organic/educational video asset if an organic template exists.
6. Multi-item templates MUST have 3-5 inventory_items with valid vehicle IDs from the "Top Vehicles" list. Spotlight templates MUST have exactly 1 inventory_item. Do NOT leave inventory_items empty for templates that require items.
7. For each non-video ad type that is enabled (image, carousel, spark), create EXACTLY 1 asset:
   - **image** (ad_format: "image"): Set template_id, avatar_id, music_id, music_name to null. template_name = "Image Ad". Provide ad_copy with primaryText, headline, description, callToAction. target_placements should be feed placements only (fb_feed, ig_feed).
   - **carousel** (ad_format: "carousel"): Set template_id, avatar_id, music_id, music_name to null. template_name = "Carousel Ad". Provide ad_copy with primaryText, headline, description, callToAction. target_placements should be feed placements only (fb_feed, ig_feed).
   - **spark** (ad_format: "spark"): Set template_id, avatar_id, music_id, music_name to null. template_name = "Spark Ad (Boosted Post)". Provide boost_metrics with budget (default 100), duration (default 7), and targetAudience. No ad_copy needed.
8. For video assets, set ad_format to "video". For organic/educational, also set ad_format to "video".
9. Pick avatars and backgrounds that match the theme vibe (for video assets only).
10. The idea_ping_summary should summarize the plan — friendly, brief, no jargon.
11. Suggest 1-2 organic post ideas that complement the paid ads theme.
12. Use ONLY the asset IDs provided in the context — do not invent IDs.
13. Assign target_placements to each asset based on the Brain's placement_mix recommendations. Focus placements should appear on most assets. Reduce placements on fewer. Excluded placements should not appear at all. Only assign placements that support the asset's type (e.g., don't put carousel on a reels placement). Use the exact placement codes from the "Available placements" list in the context.
14. Ad copy for image/carousel should be themed to match the week's creative direction. Keep primaryText under 125 chars, headline under 40 chars.
15. Video assets MUST have a non-null music_id (a valid song_id from the Music list) AND music_name (the song title).
16. Video assets MUST have a non-null background_id (a valid id from the Backgrounds list) AND background_name (the background label). The background's category MUST be in the template's bg_categories list. If the template has no bg_categories restriction, any background is allowed.
17. You MUST include inventory_target (one of the allowed values) and inventory_description (1 sentence).
18. You MUST include the experiment object with name, goal, and approach fields.
19. budget_percentage MUST be set for every paid asset (asset_type = "paid"). The values across all paid assets MUST sum to exactly 100. Allocate budget proportionally — video ads typically get the largest share, followed by image/carousel, then spark/boost.
20. For organic video assets, set organic_content_type, organic_platform, organic_day_of_week, and organic_brief. The organic_brief should describe what the post should cover.
21. Include the always_on object. Set status to "active" unless Brain data suggests pausing catalog ads. Set copy_refresh to true if it has been 2+ weeks since catalog copy was last updated (assume it needs a refresh if no data).

22. For each asset, generate a descriptive title that captures the strategic intent, NOT the template type.
Good titles explain WHY this ad was planned:
- 'Put That Refund to Work — 4 Budget Vehicles' (theme-driven)
- '3 SUVs That Need New Homes This Week' (inventory/aging stock)
- 'Spring Savings on Featured Minivans' (seasonal)
- 'Credit Score 101: What Lenders Actually Look At' (educational)
- 'Customer Spotlight: The Johnson Family' (community/organic)

Bad titles are just template names like Multi Item, Single Item Spotlight, or Educational.
The title should feel like a mini-headline that a client would understand and get excited about.

Return ONLY the JSON object, no markdown fences, no explanation.";

// If generic fallback, relax theme rules in system prompt
if (isGenericFallback) {
  systemPrompt = systemPrompt.replace(
    'The theme has already been approved by the client. You MUST use the approved theme name, emoji, seed, and direction exactly as provided. Focus on building the best possible asset plan around that theme.',
    'No specific theme was approved this week. You have creative freedom to generate an appropriate, creative theme based on Brain insights and seasonal relevance.'
  );
  systemPrompt = systemPrompt.replace(
    'Use the APPROVED THEME exactly as provided — do NOT generate a new theme name, emoji, seed, or direction.',
    'Generate an appropriate, creative theme based on Brain insights and seasonal relevance. Pick a theme name, emoji, seed, and direction that will resonate with the target audience.'
  );
  systemPrompt = systemPrompt.replace(
    '"name": "string — USE THE APPROVED THEME NAME EXACTLY"',
    '"name": "string — generate a creative, relevant theme name"'
  );
  systemPrompt = systemPrompt.replace(
    '"emoji": "string — USE THE APPROVED EMOJI EXACTLY"',
    '"emoji": "string — pick a fitting emoji for the theme"'
  );
  systemPrompt = systemPrompt.replace(
    '"theme_seed": "string — USE THE APPROVED SEED EXACTLY"',
    '"theme_seed": "string — the core concept behind the theme"'
  );
  systemPrompt = systemPrompt.replace(
    '"direction": "string — USE THE APPROVED DIRECTION EXACTLY"',
    '"direction": "string — describe how the theme should feel and look"'
  );
}

return [{ json: {
  ...data,
  _claudeBody: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 4096,
    temperature: 0.5,
    system: systemPrompt,
    messages: [
      { role: 'user', content: data._userPrompt }
    ]
  }
}}];

const promptData = $('Prepare Claude Request').first().json;
const response = $input.first().json;

let plan = null;
let parseError = '';

try {
  let text = '';
  if (response.content && response.content[0]) {
    text = response.content[0].text || '';
  } else if (response.error) {
    throw new Error('API error: ' + JSON.stringify(response.error));
  }

  // Clean markdown fences
  text = text.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  plan = JSON.parse(text);

  // Validate required fields
  if (!plan.theme || !plan.theme.name) throw new Error('Missing theme.name');
  if (!plan.theme.emoji) throw new Error('Missing theme.emoji');
  if (!plan.theme.direction) throw new Error('Missing theme.direction');
  if (!plan.assets || !Array.isArray(plan.assets)) throw new Error('Missing assets array');
  if (plan.assets.length === 0) throw new Error('Empty assets array');
  if (!plan.idea_ping_summary) throw new Error('Missing idea_ping_summary');

  // New validations for expanded fields
  if (!plan.inventory_target) throw new Error('Missing inventory_target');
  if (!plan.inventory_description) throw new Error('Missing inventory_description');
  if (!plan.experiment || !plan.experiment.name) throw new Error('Missing experiment.name');
  if (!plan.experiment.goal) throw new Error('Missing experiment.goal');
  if (!plan.experiment.approach) throw new Error('Missing experiment.approach');
  if (!plan.theme.theme_seed) throw new Error('Missing theme.theme_seed');

  // Validate video assets have music_id and background_id
  for (let i = 0; i < plan.assets.length; i++) {
    const asset = plan.assets[i];
    if (asset.ad_format === 'video') {
      if (!asset.music_id) throw new Error('Video asset ' + i + ' missing music_id');
      if (!asset.background_id) throw new Error('Video asset ' + i + ' missing background_id');
      if (!asset.music_name) throw new Error('Video asset ' + i + ' missing music_name');
      if (!asset.background_name) throw new Error('Video asset ' + i + ' missing background_name');
    }
    // Default title to template_name if Claude didn't generate one
    if (!asset.title) {
      asset.title = asset.template_name || ('Asset ' + (i + 1));
    }
  }

  // Validate budget_percentage on paid assets sums to ~100 (±2% tolerance)
  const paidAssets = plan.assets.filter(a => a.asset_type === 'paid');
  if (paidAssets.length > 0) {
    const budgetSum = paidAssets.reduce((sum, a) => sum + (parseFloat(a.budget_percentage) || 0), 0);
    if (Math.abs(budgetSum - 100) > 2) {
      // Normalize: adjust proportionally so they sum to exactly 100
      const factor = 100 / budgetSum;
      for (const a of paidAssets) {
        a.budget_percentage = Math.round((parseFloat(a.budget_percentage) || 0) * factor * 100) / 100;
      }
      // Fix rounding: adjust last asset
      const newSum = paidAssets.slice(0, -1).reduce((s, a) => s + a.budget_percentage, 0);
      paidAssets[paidAssets.length - 1].budget_percentage = Math.round((100 - newSum) * 100) / 100;
    }
  }

  // Default always_on if missing
  if (!plan.always_on) {
    plan.always_on = { status: 'active', copy_refresh: false, copy_direction: null };
  }

} catch (err) {
  parseError = err.message;
}

const isValid = plan !== null && parseError === '';

return [{ json: {
  client_id: promptData.client_id,
  client_name: promptData.client_name,
  slug: promptData.slug,
  week_start: promptData.week_start,
  week_end: promptData.week_end,
  weekly_budget: promptData.weekly_budget,
  _approvers: promptData._approvers,
  _isValid: isValid,
  _plan: plan,
  _parseError: parseError,
  _force: promptData._force
}}];

// Build INSERT data for each asset, including computed planned_outputs
const planRow = $input.first().json;
const planData = $('Validate Plan JSON').first().json;
const assets = planData._plan.assets || [];
const planId = planRow.id;

// Get placements and ad_types from the Run All Queries CTE
const queryData = $('Run All Queries').first().json;
const allPlacements = queryData.placements_data || [];
const enabledAdTypes = (queryData.ad_types || []).map(t => t.asset_type);
// Get enabled platforms from the query data
const enabledPlatforms = (queryData.platforms || []).map(p => p.platform);

// Filter placements to enabled platforms
const availablePlacements = allPlacements.filter(p => enabledPlatforms.includes(p.platform));

// Build planned_outputs for a given asset type (matches generate route logic)
function buildPlannedOutputs(assetType) {
  const supported = availablePlacements.filter(
    p => p.supported_asset_types.includes(assetType)
  );
  const byRatio = {};
  for (const p of supported) {
    for (const ratio of p.aspect_ratios) {
      if (!byRatio[ratio]) byRatio[ratio] = [];
      byRatio[ratio].push(p.code);
    }
  }
  const outputs = [];
  for (const [ratio, codes] of Object.entries(byRatio)) {
    outputs.push({ aspect_ratio: ratio, platforms: codes, credits: 1 });
  }
  // Sort: 9:16 first, then 4:5, then 16:9
  const order = ['9:16', '4:5', '16:9'];
  outputs.sort((a, b) => {
    const ai = order.indexOf(a.aspect_ratio);
    const bi = order.indexOf(b.aspect_ratio);
    return (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
  });
  return outputs;
}

// Determine ad_format from template info
function getAdFormat(asset) {
  const name = (asset.template_name || '').toLowerCase();
  if (name.includes('image')) return 'image';
  if (name.includes('carousel')) return 'carousel';
  if (name.includes('spark') || name.includes('boost')) return 'spark';
  return 'video';
}

// Escape single quotes for SQL interpolation
function escSql(str) {
  return (str || '').replace(/'/g, "''");
}


// Map template codes to video recipe slugs (Phase 2)
const TEMPLATE_TO_RECIPE = {
  'MULTI-ITEM-1': 'auto-multi-item',
  'SINGLE-ITEM-SPOTLIGHT-1': 'auto-spotlight',
  'EDUCATIONAL-1': 'edu-avatar-only'
};

// Lookup video_recipe_id from DB (fetched in Run All Queries)
const videoRecipes = queryData.video_recipes || [];
function getVideoRecipeId(templateId) {
  if (!templateId) return null;
  const slug = TEMPLATE_TO_RECIPE[templateId.toUpperCase()];
  if (!slug) return null;
  const recipe = videoRecipes.find(r => r.slug === slug);
  return recipe ? recipe.id : null;
}

return assets.map((asset, i) => {
  const adFormat = asset.ad_format || getAdFormat(asset);
  const isOrganic = asset.asset_type === 'organic';
  const isPaid = asset.asset_type === 'paid';
  const isVideo = adFormat === 'video';
  let plannedOutputs = buildPlannedOutputs(adFormat);
  // Organic/educational: typically 9:16 only
  if (isOrganic) {
    plannedOutputs = plannedOutputs.filter(o => o.aspect_ratio === '9:16');
  }

  const row = {
    plan_id: planId,
    asset_type: asset.asset_type || 'paid',
    template_id: isVideo ? (asset.template_id || null) : null,
    template_name: escSql(asset.template_name || ''),
    title: escSql(asset.title || ''),
    avatars: escSql(JSON.stringify(isVideo && asset.avatar_id ? [{ key: 'Avatar-1', avatar_id: asset.avatar_id, name: asset.avatar_name }] : [])),
    music_id: isVideo ? (asset.music_id || null) : null,
    music_name: isVideo ? escSql(asset.music_name || '') : null,
    background_id: isVideo ? (asset.background_id || null) : null,
    background_name: isVideo ? escSql(asset.background_name || '') : null,
    target_length: isVideo ? (asset.target_length || 'brief') : 'brief',
    inventory_items: escSql(JSON.stringify(asset.inventory_items || [])),
    planned_outputs: JSON.stringify(plannedOutputs),
    included: true,
    sort_order: i,
    target_placements: escSql(JSON.stringify(asset.target_placements || [])),
    ad_copy: (adFormat === 'image' || adFormat === 'carousel') && asset.ad_copy
      ? escSql(JSON.stringify(asset.ad_copy))
      : null,
    boost_content_id: adFormat === 'spark' ? (asset.boost_content_id || null) : null,
    boost_metrics: adFormat === 'spark' && asset.boost_metrics
      ? escSql(JSON.stringify(asset.boost_metrics))
      : null,
