    const ai = order.indexOf(a.aspect_ratio);
    const bi = order.indexOf(b.aspect_ratio);
    return (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
  });
  return outputs;
}

// Determine ad_format from template info
function getAdFormat(asset) {
  const name = (asset.template_name || '').toLowerCase();
  if (name.includes('image')) return 'image';
  if (name.includes('carousel')) return 'carousel';
  if (name.includes('spark') || name.includes('boost')) return 'spark';
  return 'video';
}

// Escape single quotes for SQL interpolation
function escSql(str) {
  return (str || '').replace(/'/g, "''");
}


// Map template codes to video recipe slugs (Phase 2)
const TEMPLATE_TO_RECIPE = {
  'MULTI-ITEM-1': 'auto-multi-item',
  'SINGLE-ITEM-SPOTLIGHT-1': 'auto-spotlight',
  'EDUCATIONAL-1': 'edu-avatar-only'
};

// Lookup video_recipe_id from DB (fetched in Run All Queries)
const videoRecipes = queryData.video_recipes || [];
function getVideoRecipeId(templateId) {
  if (!templateId) return null;
  const slug = TEMPLATE_TO_RECIPE[templateId.toUpperCase()];
  if (!slug) return null;
  const recipe = videoRecipes.find(r => r.slug === slug);
  return recipe ? recipe.id : null;
}

